from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to hold grouped results
    grouped_data = defaultdict(dict)

    # Helper function to extract field value from metadata
    def get_field_value(result: SearchResult, field_name: str) -> Any:
        """Extract field value from result metadata or top-level attributes."""
        # First check top-level attributes, then check metadata
        if hasattr(result, field_name):
            return getattr(result, field_name)
        return result.metadata.get(field_name)

    # Iterate through each SearchResult object
    for result in search_results:
        # Extract group value from metadata using group_by_field
        group_value = get_field_value(result, group_by_field)

        # Handle missing grouping field values by assigning to 'unknown' group
        if group_value is None:
            group_value = 'unknown'

        # Initialize group statistics if not already present
        if group_value not in grouped_data:
            grouped_data[group_value] = {
                'count': 0,
                'total_score': 0.0,
                'max_score': float('-inf'),
                'min_score': float('inf'),
                'custom_aggregations': {}
            }

        # Update default statistics
        grouped_data[group_value]['count'] += 1
        grouped_data[group_value]['total_score'] += result.score
        if result.score > grouped_data[group_value]['max_score']:
            grouped_data[group_value]['max_score'] = result.score
        if result.score < grouped_data[group_value]['min_score']:
            grouped_data[group_value]['min_score'] = result.score

    # Apply custom aggregation functions if provided
    if aggregation_funcs:
        for group_value, stats in grouped_data.items():
            for field_name, func in aggregation_funcs.items():
                # Collect field values for custom aggregation
                field_values = []
                for result in search_results:
                    field_value = get_field_value(result, field_name)
                    field_values.append(field_value)

                try:
                    # Apply the custom aggregation function
                    aggregation_result = func(field_values)
                    stats['custom_aggregations'][field_name] = aggregation_result
                except Exception as e:
                    # Handle any errors during aggregation
                    stats['custom_aggregations'][field_name] = f"Error: {str(e)}"

    # Convert defaultdict to regular dict and calculate final statistics
    final_results = {}
    for group_value, stats in grouped_data.items():
        # Calculate average score
        avg_score = stats['total_score'] / stats['count'] if stats['count'] > 0 else 0.0

        # Combine default and custom statistics
        group_stats = {
            'count': stats['count'],
            'avg_score': round(avg_score, 4),
            'max_score': stats['max_score'],
            'min_score': stats['min_score']
        }

        # Add custom aggregations if they exist
        if stats['custom_aggregations']:
            group_stats.update(stats['custom_aggregations'])

        final_results[group_value] = group_stats

    return final_results
